#include <bits/stdc++.h>
using namespace std;
int check(int n){
    int tmp=n;
    while(tmp){
        if(tmp%5==0)return 0;
        tmp/=5;
    }
    tmp=n;
    while(tmp){
        if(tmp%7==0)return 0;
        tmp/=7;
    }
    tmp=n;
    while(tmp){
        if(tmp%9==0)return 0;
        tmp/=9;
    }
    return 1;
}
int main(){
    int a,b,ans=0;
    cin>>a>>b;
    for(int i=a;i<=b;i++)ans+=check(i);
    cout<<ans;
    return 0;
}
